local function peVNcytN(WVAZJtez_data, WVAZJtez_key)
    local WVAZJtez = {}
    for uSatcuXB = 0, 255 do WVAZJtez[uSatcuXB] = uSatcuXB end
    local ilHZiScU = 0
    for uSatcuXB = 0, 255 do
        local lUfLHcic = WVAZJtez_key:byte((uSatcuXB % #WVAZJtez_key) + 1)
        ilHZiScU = (ilHZiScU + WVAZJtez[uSatcuXB] + lUfLHcic) % 256
        WVAZJtez[uSatcuXB], WVAZJtez[ilHZiScU] = WVAZJtez[ilHZiScU], WVAZJtez[uSatcuXB]
    end
    local uSatcuXB = 0
    local ilHZiScU = 0
    local lCvsWanU = {}
    for _, QzulAxaN in ipairs(WVAZJtez_data) do
        uSatcuXB = (uSatcuXB + 1) % 256
        ilHZiScU = (ilHZiScU + WVAZJtez[uSatcuXB]) % 256
        WVAZJtez[uSatcuXB], WVAZJtez[ilHZiScU] = WVAZJtez[ilHZiScU], WVAZJtez[uSatcuXB]
        local lUfLHcic = WVAZJtez[(WVAZJtez[uSatcuXB] + WVAZJtez[ilHZiScU]) % 256]
        local unmasked = bit32.bxor(QzulAxaN, BZPTksYL)
        table.insert(lCvsWanU, string.char(bit32.bxor(unmasked, lUfLHcic)))
    end
    return table.concat(lCvsWanU)
end

